17	const RUNE_TYPE = "rune";
18	const PROCESSING_FEE = 5;
19	const BLOCK_SIZE = 3;
20	const RUNE_BLOCK_PREMIUM = 60;
21	const FIRST_INSURANCE_RATE = 0.1;
22	const LOYALTY_RATE = 0.2;
23	const LOYALTY_MIN_YEARS = 2;
24	const CURSE_SURCHARGE_RATE = 0.5;
25	const HIGH_ENCHANTMENT_RATE = 0.3;
26	const HIGH_ENCHANTMENT_THRESHOLD = 5;
27	
28	const BASE_PREMIUMS: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  rune: 25,
34	};
35	
36	const unitPriceFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;
37	
38	const isRune = (item: Item): boolean => item.type === RUNE_TYPE;
39	
40	const isMainItem = (item: Item): boolean => !isRune(item);
41	
42	const runeBasePremium = (runeCount: number): number =>
43	  runeCount === BLOCK_SIZE
44	    ? RUNE_BLOCK_PREMIUM
45	    : runeCount * unitPriceFor(RUNE_TYPE);
46	
47	const sumOver = (items: Item[], valueOf: (item: Item) => number): number =>
48	  items.reduce((sum, item) => sum + valueOf(item), 0);
49	
50	const sumUnitPrices = (items: Item[]): number =>
51	  sumOver(items, (item) => unitPriceFor(item.type));
52	
53	const countRunes = (items: Item[]): number => items.filter(isRune).length;
54	
55	const totalBasePremium = (items: Item[]): number =>
56	  sumUnitPrices(items.filter(isMainItem)) + runeBasePremium(countRunes(items));
57	
58	const isHighlyEnchanted = (item: Item): boolean =>
59	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
60	
61	const itemSurchargeRate = (item: Item): number =>
62	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
63	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
64	
65	const itemSurcharges = (item: Item): number =>
66	  unitPriceFor(item.type) * itemSurchargeRate(item);
67	
68	const totalSurcharges = (items: Item[]): number =>
69	  sumOver(items, itemSurcharges);
70	
71	const firstInsuranceSurcharge = (policyBase: number): number =>
72	  policyBase * FIRST_INSURANCE_RATE;
73	
74	const isLoyal = (customer: Customer): boolean =>
75	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS;
76	
77	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
78	  isLoyal(customer) ? policyBase * LOYALTY_RATE : 0;
79	
80	export const quote = (input: QuoteInput): number => {
81	  const policyBase = totalBasePremium(input.items);
82	  const premiumBeforeFee =
83	    policyBase +
84	    totalSurcharges(input.items) +
85	    firstInsuranceSurcharge(policyBase) -
86	    loyaltyDiscount(policyBase, input.customer);
87	  return Math.ceil(premiumBeforeFee + PROCESSING_FEE);
88	};
