const CURSED_SURCHARGE = 30;

function policyAmountFor(policyBase: number, modifier?: ClaimRequest["modifier"]): number {
  if (modifier === "haunted") return policyBase * 1.5;
  if (modifier === "blessed") return policyBase * 0.8;
  return policyBase;
}

function itemAmountFor(item: Item): number {
  return item.kind === "cursed" ? item.base + CURSED_SURCHARGE : item.base;
}

export function claimOffice(request: ClaimRequest): number {
  const { policyBase, modifier, items = [] } = request;

  const policyAmount = policyAmountFor(policyBase, modifier);
  const itemsTotal = items.reduce((total, item) => total + itemAmountFor(item), 0);

  return policyAmount + itemsTotal;
}

